// .claude/tools/config-manager.ts
// 自动化配置管理工具 - 支持多环境配置模板化

import { z } from 'zod';
import { ConfigLoader } from './loaders';
import { ConfigValidator } from './validators';

// 配置 schema 定义
const EnvironmentSchema = z.object({
  node: z.string(),
  apiUrl: z.string().url(),
  database: z.object({
    host: z.string(),
    port: z.number(),
    name: z.string(),
  }),
  features: z.record(z.boolean()),
});

type Environment = z.infer<typeof EnvironmentSchema>;

class ConfigManager {
  private configs: Map<string, Environment> = new Map();
  private validator: ConfigValidator;

  constructor() {
    this.validator = new ConfigValidator(EnvironmentSchema);
  }

  /**
   * 加载环境配置
   * @param env 环境名称 (development, staging, production)
   */
  async loadEnvironment(env: string): Promise<Environment> {
    // 1. 加载默认配置
    const defaultConfig = await ConfigLoader.load('.env.defaults');

    // 2. 加载环境特定配置
    const envConfig = await ConfigLoader.load(`.env.${env}`);

    // 3. 合并配置（环境配置覆盖默认配置）
    const merged = this.mergeConfigs(defaultConfig, envConfig);

    // 4. 验证配置
    const validated = await this.validator.validate(merged);

    // 5. 缓存配置
    this.configs.set(env, validated);

    return validated;
  }

  /**
   * 获取配置，支持类型安全的访问
   */
  get<K extends keyof Environment>(
    env: string,
    key: K
  ): Environment[K] {
    const config = this.configs.get(env);
    if (!config) {
      throw new Error(`Environment "${env}" not loaded`);
    }
    return config[key];
  }

  /**
   * 生成环境配置文件
   */
  async generateEnvFile(
    template: string,
    output: string,
    variables: Record<string, string>
  ): Promise<void> {
    // 读取模板
    let content = await ConfigLoader.load(template);

    // 替换变量
    for (const [key, value] of Object.entries(variables)) {
      content = content.replace(
        new RegExp(`\$\{${key}\}`, 'g'),
        value
      );
    }

    // 写入文件
    await fs.writeFile(output, content);

    console.log(`✅ 已生成配置文件: ${output}`);
  }

  /**
   * 导出配置为 TypeScript 常量
   */
  async exportAsConstants(env: string): Promise<string> {
    const config = await this.loadEnvironment(env);

    return `// 自动生成 - 请勿手动修改
// 生成时间: ${new Date().toISOString()}

export const config = ${JSON.stringify(config, null, 2)} as const;

export type Config = typeof config;
`;
  }

  private mergeConfigs(
    base: Record<string, any>,
    override: Record<string, any>
  ): Record<string, any> {
    const result = { ...base };

    for (const key of Object.keys(override)) {
      if (
        typeof base[key] === 'object' &&
        typeof override[key] === 'object' &&
        !Array.isArray(base[key])
      ) {
        result[key] = this.mergeConfigs(base[key], override[key]);
      } else {
        result[key] = override[key];
      }
    }

    return result;
  }
}

// 使用示例
async function main() {
  const manager = new ConfigManager();

  // 加载开发环境配置
  const devConfig = await manager.loadEnvironment('development');
  console.log('开发环境配置:', devConfig);

  // 生成环境文件
  await manager.generateEnvFile(
    '.env.template',
    '.env.development',
    {
      NODE_ENV: 'development',
      API_URL: devConfig.apiUrl,
      DB_HOST: devConfig.database.host,
      DB_PORT: devConfig.database.port.toString(),
    }
  );

  // 导出 TypeScript 常量
  const constants = await manager.exportAsConstants('development');
  await fs.writeFile('src/config.ts', constants);
}

main().catch(console.error);
