### 示例 2

```python
// 示例 2: 代码批量修改任务
// 场景：将 src 目录下所有 .js 文件中的 console.log 替换为 logger.info

/*
用户输入: "将 src 目录下所有 JS 文件中的 console.log 替换为 logger.info"

AI Agent 的工作流程:
1. 扫描 src/**/*.js 文件
2. 识别包含 console.log 的文件
3. 执行批量替换
4. 报告修改的文件数量和行数
*/

// 模拟实现（Node.js 伪代码）
const fs = require('fs');
const path = require('path');

class CodeModifier {
  constructor(sourceDir) {
    this.sourceDir = sourceDir;
    this.changes = [];
  }

  // 扫描目录下所有 JS 文件
  scanFiles(dir = this.sourceDir) {
    const files = [];
    const entries = fs.readdirSync(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        files.push(...this.scanFiles(fullPath));
      } else if (entry.name.endsWith('.js')) {
        files.push(fullPath);
      }
    }
    return files;
  }

  // 替换文件内容
  replaceInFile(filePath, pattern, replacement) {
    let content = fs.readFileSync(filePath, 'utf-8');
    const originalContent = content;

    // 执行替换
    content = content.replace(new RegExp(pattern, 'g'), replacement);

    // 如果内容有变化，写回文件
    if (content !== originalContent) {
      fs.writeFileSync(filePath, content);
      this.changes.push({
        file: filePath,
        replacements: (originalContent.match(new RegExp(pattern, 'g')) || []).length
      });
    }
  }

  // 执行批量替换任务
  executeReplacement(pattern, replacement) {
    const files = this.scanFiles();

    files.forEach(file => {
      this.replaceInFile(file, pattern, replacement);
    });

    return {
      totalFiles: files.length,
      modifiedFiles: this.changes.length,
      details: this.changes
    };
  }
}

// 使用示例
const modifier = new CodeModifier('./src');
const result = modifier.executeReplacement(
  'console\\.log',           // 匹配 console.log (需要转义)
  'logger.info'              // 替换为 logger.info
);

console.log(`已修改 ${result.modifiedFiles} 个文件，共 ${result.totalFiles} 个文件`);
result.details.forEach(d => {
  console.log(`  - ${d.file}: ${d.replacements} 处修改`);
});
```

### 示例 3

```python
// 示例 3: Git 操作辅助
// 场景：自动分析 git 状态并给出操作建议

/*
用户输入: "分析当前的 git 状态，告诉我需要做什么"

AI Agent 会:
1. 执行 git status 获取状态
2. 执行 git diff 查看变更详情
3. 分析变更内容
4. 给出操作建议
*/

// 模拟实现
class GitAssistant {
  constructor() {
    this.commands = {
      status: 'git status --short',
      diff: 'git diff --stat',
      branch: 'git branch --show-current',
      staged: 'git diff --cached --stat'
    };
  }

  // 执行命令并返回结果
  async executeCommand(cmd) {
    // 实际实现会调用 shell 命令
    return await this.runShell(cmd);
  }

  // 分析仓库状态
  async analyzeStatus() {
    const status = await this.executeCommand(this.commands.status);
    const branch = await this.executeCommand(this.commands.branch);
    const staged = await this.executeCommand(this.commands.staged);

    return {
      currentBranch: branch.trim(),
      untrackedFiles: this.parseStatus(status, '??'),
      modifiedFiles: this.parseStatus(status, ' M'),
      stagedFiles: this.parseStatus(status, '
M '), // 空格 M 表示已暂存
      stagedSummary: staged.trim()
    };
  }

  // 解析状态输出
  parseStatus(output, prefix) {
    return output
      .split('\n')
      .filter(line => line.startsWith(prefix))
      .map(line => line.substring(3).trim());
  }

  // 生成操作建议
  generateSuggestions(status) {
    const suggestions = [];

    if (status.untrackedFiles.length > 0) {
      suggestions.push({
        action: 'git add <files>',
        description: `添加 ${status.untrackedFiles.length} 个未跟踪文件`,
        autoCommand: `git add ${status.untrackedFiles.join(' ')}`
      });
    }

    if (status.modifiedFiles.length > 0) {
      suggestions.push({
        action: 'git diff / git add',
        description: `有 ${status.modifiedFiles.length} 个文件已修改`,
        hint: '使用 git diff 查看具体变更，或 git add 暂存修改'
      });
    }

    if (status.stagedFiles.length > 0) {
      suggestions.push({
        action: 'git commit',
        description: `已暂存 ${status.stagedFiles.length} 个文件的修改`,
        hint: '使用 git commit -m "message" 提交'
      });
    }

    return suggestions;
  }
}

// 使用示例
async function main() {
  const assistant = new GitAssistant();
  const status = await assistant.analyzeStatus();
  const suggestions = assistant.generateSuggestions(status);

  console.log(`📍 当前分支: ${status.currentBranch}\n`);

  if (suggestions.length === 0) {
    console.log('✨ 工作区干净，无需操作');
  } else {
    console.log('💡 建议操作:\n');
    suggestions.forEach((s, i) => {
      console.log(`${i + 1}. ${s.description}`);
      console.log(`   命令: ${s.action}`);
      if (s.autoCommand) {
        console.log(`   自动执行: ${s.autoCommand}`);
      }
      console.log('');
    });
  }
}

// main(); // 解注以运行
```



## 常见错误

- 将终端 AI Agent 视为完全可靠的全能工具，盲目执行所有建议而忽视人工审核
- 指令过于模糊或含糊，导致 AI 理解偏差，执行了不符合预期的操作
- 在生产环境或重要目录中直接运行未经测试的命令
- 忽略安全警告和权限限制提示，强行执行危险操作
- 期望 AI 完全理解复杂业务逻辑，生成代码缺乏必要的业务上下文
- 不检查生成代码的正确性就直接运行，导致文件损坏或数据丢失
- 混淆不同工具的功能范围，用聊天机器人的方式使用终端 AI Agent


## 最佳实践

- 从简单任务开始学习：先用 AI 执行创建文件、查看目录等基础操作，熟悉工具响应方式后再尝试复杂任务
- 始终保持批判性思维：对 AI 生成的命令和代码进行人工审核，特别是涉及文件操作和系统配置的场景
- 使用渐进式指令：将复杂任务分解为多个简单步骤，逐步验证每步结果后再继续
- 充分利用预览和模拟模式：多数 AI Agent 提供干运行(dry-run)或预览模式，先检查操作计划再实际执行
- 建立项目规范：在项目根目录添加 .ai-config 或 CLAUDE.md 文件，让 AI 理解项目的代码规范和特殊要求
- 善用版本控制：在执行批量修改前确保工作区已提交，或在修改后仔细检查 diff 结果
- 保持安全意识：了解工具的权限配置，对敏感操作（如 rm -rf）保持警惕，建议启用操作审计日志
- 掌握多工具配合：将 AI Agent 与传统 CLI、IDE 工具结合使用，发挥各自优势
- 定期回顾交互记录：通过分析历史对话日志，优化自己的指令方式和 AI 的响应质量

