    const branch = await this.executeCommand(this.commands.branch);
    const staged = await this.executeCommand(this.commands.staged);

    return {
      currentBranch: branch.trim(),
      untrackedFiles: this.parseStatus(status, '??'),
      modifiedFiles: this.parseStatus(status, ' M'),
      stagedFiles: this.parseStatus(status, '
M '), // 空格 M 表示已暂存
      stagedSummary: staged.trim()
    };
  }

  // 解析状态输出
  parseStatus(output, prefix) {
    return output
      .split('\n')
      .filter(line => line.startsWith(prefix))
      .map(line => line.substring(3).trim());
  }

  // 生成操作建议
  generateSuggestions(status) {
    const suggestions = [];

    if (status.untrackedFiles.length > 0) {
      suggestions.push({
        action: 'git add <files>',
        description: `添加 ${status.untrackedFiles.length} 个未跟踪文件`,
        autoCommand: `git add ${status.untrackedFiles.join(' ')}`
      });
    }

    if (status.modifiedFiles.length > 0) {
      suggestions.push({
        action: 'git diff / git add',
        description: `有 ${status.modifiedFiles.length} 个文件已修改`,
        hint: '使用 git diff 查看具体变更，或 git add 暂存修改'
      });
    }

    if (status.stagedFiles.length > 0) {
      suggestions.push({
        action: 'git commit',
        description: `已暂存 ${status.stagedFiles.length} 个文件的修改`,
        hint: '使用 git commit -m "message" 提交'
      });
    }

    return suggestions;
  }
}

// 使用示例
async function main() {
  const assistant = new GitAssistant();
  const status = await assistant.analyzeStatus();
  const suggestions = assistant.generateSuggestions(status);

  console.log(`📍 当前分支: ${status.currentBranch}\n`);

  if (suggestions.length === 0) {
    console.log('✨ 工作区干净，无需操作');
  } else {
    console.log('💡 建议操作:\n');
    suggestions.forEach((s, i) => {
      console.log(`${i + 1}. ${s.description}`);
      console.log(`   命令: ${s.action}`);
      if (s.autoCommand) {
        console.log(`   自动执行: ${s.autoCommand}`);
      }
      console.log('');
    });
  }
}

