// .claude/commands/init-project.ts
// AI Agent 初始化项目命令

import { ProjectGenerator } from '@openclaw/generator';
import { FileWriter } from '@openclaw/fs';
import { DependencyManager } from '@openclaw/deps';

interface ProjectConfig {
  name: string;
  frontend: {
    framework: 'vue' | 'react' | 'svelte';
    language: 'typescript' | 'javascript';
    uiLibrary?: string;
  };
  backend: {
    framework: 'express' | 'fastify' | 'nest';
    database?: 'postgresql' | 'mysql' | 'mongodb';
    orm?: 'prisma' | 'typeorm';
  };
  features: string[];
}

class ProjectInitializer {
  constructor(private config: ProjectConfig) {}

  async initialize(): Promise<void> {
    console.log('🚀 开始初始化项目...');

    // 1. 创建项目目录结构
    await this.createStructure();

    // 2. 生成配置文件
    await this.generateConfigs();

    // 3. 创建代码模板
    await this.generateTemplates();

    // 4. 安装依赖
    await this.installDependencies();

    // 5. 初始化 Git
    await this.initGit();

    console.log('✅ 项目初始化完成！');
    this.printNextSteps();
  }

  private async createStructure(): Promise<void> {
    const structure = {
      root: [
        '.vscode',
        'docs',
        'packages/web/src',
        'packages/web/public',
        'packages/api/src',
        'packages/api/prisma',
      ],
      configs: [
        '.gitignore',
        '.eslintrc.js',
        '.prettierrc',
        'package.json',
        'pnpm-workspace.yaml',
      ],
    };

    // 创建目录结构
    for (const dir of structure.root) {
      await FileWriter.ensureDir(dir);
    }
    console.log('📁 目录结构已创建');
  }

  private async generateConfigs(): Promise<void> {
    // 生成 package.json
    await FileWriter.write('package.json', JSON.stringify({
      name: this.config.name,
      version: '1.0.0',
      private: true,
      workspaces: ['packages/*'],
      scripts: {
        dev: 'pnpm -r --parallel run dev',
        build: 'pnpm -r run build',
        lint: 'pnpm -r run lint',
        test: 'pnpm -r run test',
      },
    }, null, 2));

    // 生成 monorepo 配置
    await FileWriter.write('pnpm-workspace.yaml', 'packages:\n  - "packages/*"\n');

    console.log('⚙️ 配置文件已生成');
  }

  private async generateTemplates(): Promise<void> {
    const generator = new ProjectGenerator(this.config);

    // 生成前端代码模板
    await generator.generateFrontend();

    // 生成后端代码模板
    await generator.generateBackend();

    // 生成共享类型（如果需要）
    if (this.config.features.includes('shared-types')) {
      await generator.generateSharedTypes();
    }

    console.log('📝 代码模板已生成');
  }

  private async installDependencies(): Promise<void> {
    const deps = new DependencyManager();

    // 前端依赖
    await deps.addWorkspace({
      workspace: 'packages/web',
      deps: [
        `vue@^3.4.0`,
        `${this.config.frontend.language}@^5.0.0`,
        'vite@^5.0.0',
        '@vitejs/plugin-vue',
        'pinia',
        'axios',
      ],
      devDeps: [
        'eslint',
        'prettier',
        '@types/node',
      ],
    });

    // 后端依赖
    await deps.addWorkspace({
      workspace: 'packages/api',
      deps: [
        `${this.config.backend.framework}`,
        `${this.config.backend.orm || 'prisma'}@^5.0.0`,
        'cors',
        'helmet',
        '@prisma/client',
      ],
      devDeps: [
        'typescript',
        'eslint',
        'prisma',
      ],
    });

    console.log('📦 依赖安装完成');
  }

  private async initGit(): Promise<void> {
    // 初始化 Git 仓库
    await Command.run('git', ['init']);

    // 创建初始提交
    await Command.run('git', ['add', '.']);
    await Command.run('git', ['commit', '-m', 'feat: initial project setup']);

    console.log('🔧 Git 仓库已初始化');
  }

  private printNextSteps(): void {
    console.log('\n📋 下一步操作：');
    console.log('  1. cd packages/web && pnpm dev    # 启动前端开发服务器');
    console.log('  2. cd packages/api && pnpm dev   # 启动后端开发服务器');
    console.log('  3. pnpm build                    # 构建项目');
    console.log('\n📚 详细文档请查看 README.md');
  }
}

